mapper.select:
SELECT id, action, entity_type, entity_id, user_id, old_value, new_value, ip_address, created_at
FROM audit_logs


        action LIKE CONCAT('%', #{action}, '%')


        AND entity_type = #{entityType}


        AND user_id = #{userId}


        AND (
            old_value LIKE CONCAT('%', #{keyword}, '%')
            OR new_value LIKE CONCAT('%', #{keyword}, '%')
            OR ip_address LIKE CONCAT('%', #{keyword}, '%')
        )


        AND created_at >= #{fromAt}


        AND created_at < #{toAtExclusive}


ORDER BY id DESC
LIMIT #{limit}
